import{_ as e,c as s}from"./app.0b00aae6.js";const P={},p=s('<h1 id="_23-\u8BB2-\u77E5\u5176\u7136\u77E5\u5176\u6240\u4EE5\u7136-\u804A\u804A-api-\u81EA\u52A8\u5316\u6D4B\u8BD5\u6846\u67B6\u7684\u524D\u4E16\u4ECA\u751F" tabindex="-1"><a class="header-anchor" href="#_23-\u8BB2-\u77E5\u5176\u7136\u77E5\u5176\u6240\u4EE5\u7136-\u804A\u804A-api-\u81EA\u52A8\u5316\u6D4B\u8BD5\u6846\u67B6\u7684\u524D\u4E16\u4ECA\u751F" aria-hidden="true">#</a> 23 \u8BB2\uFF1A\u77E5\u5176\u7136\u77E5\u5176\u6240\u4EE5\u7136\uFF1A\u804A\u804A API \u81EA\u52A8\u5316\u6D4B\u8BD5\u6846\u67B6\u7684\u524D\u4E16\u4ECA\u751F</h1><p>\u4F60\u597D\uFF0C\u6211\u662F\u8339\u70B3\u665F\uFF0C\u4ECA\u5929\u6211\u548C\u4F60\u5206\u4EAB\u7684\u4E3B\u9898\u662F\u201C\u77E5\u5176\u7136\u77E5\u5176\u6240\u4EE5\u7136\uFF1A\u804A\u804A API \u81EA\u52A8\u5316\u6D4B\u8BD5\u6846\u67B6\u7684\u524D\u4E16\u4ECA\u751F\u201D\u3002</p><p>\u5728\u4E0A\u4E00\u7BC7\u6587\u7AE0\u4E2D\uFF0C\u6211\u4EE5\u4E00\u4E2A\u7B80\u5355\u7684 Restful API \u4E3A\u4F8B\uFF0C\u5206\u522B\u4ECB\u7ECD\u4E86 cURL \u548C Postman \u7684\u4F7F\u7528\u65B9\u6CD5\uFF0C\u76F8\u4FE1\u4F60\u5DF2\u7ECF\u5BF9 API \u6D4B\u8BD5\u6709\u4E2A\u611F\u6027\u8BA4\u8BC6\u4E86\u3002</p><p>\u4F46\u662F\uFF0C\u6211\u4EEC\u4E0D\u80FD\u4EC5\u4EC5\u505C\u7559\u5728\u611F\u6027\u8BA4\u8BC6\u7684\u5C42\u9762\uFF0C\u8FD8\u9700\u8981\u719F\u6089\u5E76\u638C\u63E1\u8FD9\u4E9B\u6D4B\u8BD5\u65B9\u6CD5\uFF0C\u5B8C\u6210\u76F8\u5E94\u7684 API \u6D4B\u8BD5\u5DE5\u4F5C\u3002\u6240\u4EE5\uFF0C\u4E5F\u5C31\u6709\u4E86\u6211\u4ECA\u5929\u5206\u4EAB\u7684\u4E3B\u9898\uFF0C\u5E0C\u671B\u53EF\u4EE5\u901A\u8FC7\u5BF9 API \u81EA\u52A8\u5316\u6D4B\u8BD5\u6846\u67B6\u53D1\u5C55\u7684\u4ECB\u7ECD\uFF0C\u8BA9\u4F60\u7406\u89E3 API \u6D4B\u8BD5\u662F\u5982\u4F55\u4E00\u6B65\u4E00\u6B65\u5730\u53D1\u5C55\u6210\u4ECA\u5929\u7684\u6837\u5B50\uFF0C\u4EE5\u201C\u77E5\u5176\u6240\u4EE5\u7136\u201D\u7684\u65B9\u5F0F\u52A0\u6DF1\u4F60\u5BF9 API \u81EA\u52A8\u5316\u6D4B\u8BD5\u7684\u7406\u89E3\u3002</p><p>\u63A5\u4E0B\u6765\uFF0C\u6211\u5C06\u4F1A\u9075\u5FAA\u7531\u7B80\u5165\u7E41\u7684\u539F\u5219\uFF0C\u4E3A\u4F60\u4ECB\u7ECD API \u6D4B\u8BD5\u6846\u67B6\uFF0C\u4EE5\u53D1\u73B0\u95EE\u9898\u7136\u540E\u89E3\u51B3\u95EE\u9898\u7684\u601D\u8DEF\u4E3A\u4E3B\u7EBF\uFF0C\u5C55\u5F00\u4ECA\u5929\u7684\u5206\u4EAB\u3002</p><p><strong>\u65E9\u671F\u7684\u57FA\u4E8E Postman \u7684 API \u6D4B\u8BD5</strong></p><p>\u65E9\u671F\u7684 API \u6D4B\u8BD5\uFF0C\u5F80\u5F80\u90FD\u662F\u901A\u8FC7\u7C7B\u4F3C Postman \u7684\u5DE5\u5177\u5B8C\u6210\u7684\u3002\u4F46\u662F\uFF0C\u7531\u4E8E\u8FD9\u7C7B\u5DE5\u5177\u90FD\u662F\u57FA\u4E8E\u754C\u9762\u64CD\u4F5C\u7684\uFF0C\u6240\u4EE5\u6709\u4EE5\u4E0B\u4E24\u4E2A\u95EE\u9898\u4E9F\u5F85\u89E3\u51B3\uFF1A</p><ol><li>\u5F53\u9700\u8981\u9891\u7E41\u6267\u884C\u5927\u91CF\u7684\u6D4B\u8BD5\u7528\u4F8B\u65F6\uFF0C\u57FA\u4E8E\u754C\u9762\u7684 API \u6D4B\u8BD5\u5C31\u663E\u5F97\u6709\u4E9B\u7B28\u62D9\uFF1B</li><li>\u57FA\u4E8E\u754C\u9762\u64CD\u4F5C\u7684\u6D4B\u8BD5\u96BE\u4EE5\u4E0E CI/CD \u6D41\u6C34\u7EBF\u96C6\u6210\u3002</li></ol><p>\u6240\u4EE5\uFF0C\u6211\u4EEC\u8FEB\u5207\u9700\u8981\u4E00\u5957\u53EF\u4EE5\u57FA\u4E8E\u547D\u4EE4\u884C\u6267\u884C\u7684 API \u6D4B\u8BD5\u65B9\u6848\u3002\u8FD9\u6837\uFF0CAPI \u6D4B\u8BD5\u53EF\u4EE5\u76F4\u63A5\u901A\u8FC7\u547D\u4EE4\u884C\u53D1\u8D77\uFF0C\u4E0E CI/CD \u6D41\u6C34\u7EBF\u7684\u6574\u5408\u4E5F\u5C31\u65B9\u4FBF\u5F97\u591A\u4E86\u3002</p><p><strong>\u57FA\u4E8E Postman \u548C Newman \u7684 API \u6D4B\u8BD5</strong></p><p>\u4E8E\u662F\u5C31\u51FA\u73B0\u4E86\u96C6\u6210 Postman \u548C Newman \u7684\u65B9\u6848\uFF0C\u7136\u540E\u518D\u7ED3\u5408 Jenkins \u5C31\u53EF\u4EE5\u5F88\u65B9\u4FBF\u5730\u5B9E\u73B0 API \u6D4B\u8BD5\u4E0E CI/CDl \u6D41\u6C34\u7EBF\u7684\u96C6\u6210\u3002Newman \u5176\u5B9E\u5C31\u662F\u4E00\u4E2A\u547D\u4EE4\u884C\u5DE5\u5177\uFF0C\u53EF\u4EE5\u76F4\u63A5\u6267\u884C Postman \u5BFC\u51FA\u7684\u6D4B\u8BD5\u7528\u4F8B\u3002</p><p>\u7528 Postman \u5F00\u53D1\u8C03\u8BD5\u6D4B\u8BD5\u7528\u4F8B\uFF0C\u5B8C\u6210\u540E\u901A\u8FC7 Newman \u6267\u884C\uFF0C\u8FD9\u4E2A\u65B9\u6848\u770B\u4F3C\u5F88\u5B8C\u7F8E\u3002\u4F46\u662F\u5728\u5B9E\u9645\u5DE5\u7A0B\u5B9E\u8DF5\u4E2D\uFF0C\u6D4B\u8BD5\u573A\u666F\u9664\u4E86\u7B80\u5355\u8C03\u7528\u5355\u4E2A API \u4EE5\u5916\uFF0C\u8FD8\u5B58\u5728\u8FDE\u7EED\u8C03\u7528\u591A\u4E2A API \u7684\u60C5\u51B5\u3002</p><p>\u6B64\u65F6\uFF0C\u5F80\u5F80\u4F1A\u6D89\u53CA\u5230\u591A\u4E2A API \u8C03\u7528\u65F6\u7684\u6570\u636E\u4F20\u9012\u95EE\u9898\uFF0C\u5373\u4E0B\u4E00\u4E2A API \u8C03\u7528\u7684\u53C2\u6570\u53EF\u80FD\u662F\u4E0A\u4E00\u4E2A API \u8C03\u7528\u8FD4\u56DE\u7ED3\u679C\u4E2D\u7684\u67D0\u4E2A\u503C\u3002\u53E6\u5916\uFF0C\u8FD8\u4F1A\u7ECF\u5E38\u9047\u5230\u7684\u60C5\u51B5\u662F\uFF0CAPI \u8C03\u7528\u524D\u9700\u8981\u5148\u6267\u884C\u4E00\u4E9B\u7279\u5B9A\u7684\u64CD\u4F5C\uFF0C\u6BD4\u5982\u51C6\u5907\u6D4B\u8BD5\u6570\u636E\u7B49\u3002</p><p>\u56E0\u6B64\uFF0C\u5BF9\u4E8E\u9700\u8981\u8FDE\u7EED\u8C03\u7528\u591A\u4E2A API \u5E76\u4E14\u6709\u53C2\u6570\u4F20\u9012\u7684\u60C5\u51B5\uFF0CPostman+Newman \u4F3C\u4E4E\u5C31\u4E0D\u518D\u662F\u7406\u60F3\u7684\u6D4B\u8BD5\u65B9\u6848\u4E86\u3002</p><p><strong>\u57FA\u4E8E\u4EE3\u7801\u7684 API \u6D4B\u8BD5</strong></p><p>\u4E3A\u4E86\u89E3\u51B3\u8FD9\u4E2A\u95EE\u9898\uFF0C\u4E8E\u662F\u5C31\u51FA\u73B0\u4E86\u57FA\u4E8E\u4EE3\u7801\u7684 API \u6D4B\u8BD5\u6846\u67B6\u3002\u6BD4\u8F83\u5178\u578B\u7684\u662F\uFF0C\u57FA\u4E8E Java \u7684 OkHttP \u548C Unirest\u3001\u57FA\u4E8E Python \u7684 http.client \u548C Requests\u3001\u57FA\u4E8E NodeJS \u7684 Native \u548C Request \u7B49\u3002</p><p>\u5C0F\u578B\u7684\u4E92\u8054\u7F51\u4F01\u4E1A\uFF0C\u5F80\u5F80\u4F1A\u6839\u636E\u81EA\u5DF1\u7684\u4E1A\u52A1\u9700\u6C42\uFF0C\u9009\u7528\u8FD9\u4E9B\u6210\u719F\u7684 API \u6D4B\u8BD5\u6846\u67B6\u3002</p><p>\u4F46\u662F\uFF0C\u5BF9\u4E8E\u4E2D\u5927\u578B\u7684\u4E92\u8054\u7F51\u4F01\u4E1A\uFF0C\u4E00\u822C\u90FD\u4F1A\u81EA\u5DF1\u5F00\u53D1\u66F4\u9002\u5408\u81EA\u8EAB\u4E1A\u52A1\u4E0A\u4E0B\u6587\u7684 API \u6D4B\u8BD5\u6846\u67B6\uFF0C\u6BD4\u5982 eBay\uFF0C\u6211\u4EEC\u4E3A\u4E86\u5B9E\u73B0\u4EE3\u7801\u5316\u7684 API \u6D4B\u8BD5\uFF0C\u5F00\u53D1\u4E86\u81EA\u5DF1\u7684 HttpClient\uFF0C\u540E\u671F\u4E3A\u4E86\u4F7F API \u6D4B\u8BD5\u7684\u4EE3\u7801\u66F4\u7B80\u6D01\u6613\u61C2\uFF0C\u5C31\u57FA\u4E8E Rest-Assured \u5C01\u88C5\u4E86\u5168\u65B0\u7684 API \u6D4B\u8BD5\u6846\u67B6\u3002</p><p>\u8FD9\u79CD\u6839\u636E\u516C\u53F8\u4E1A\u52A1\u4E0A\u4E0B\u6587\u5F00\u53D1\u5B9E\u73B0\u7684 API \u6D4B\u8BD5\u6846\u67B6\uFF0C\u5728\u4F7F\u7528\u4E0A\u6709\u5F88\u591A\u4F18\u70B9\uFF0C\u800C\u4E14\u7075\u6D3B\u6027\u4E5F\u5F88\u597D\uFF0C\u4E3B\u8981\u4F53\u73B0\u5728\u4EE5\u4E0B\u51E0\u4E2A\u65B9\u9762\uFF1A</p><ol><li>\u53EF\u4EE5\u7075\u6D3B\u652F\u6301\u591A\u4E2A API \u7684\u987A\u5E8F\u8C03\u7528\uFF0C\u65B9\u4FBF\u6570\u636E\u5728\u591A\u4E2A API \u4E4B\u95F4\u4F20\u9012\uFF0C\u5373\u4E0A\u4E00\u4E2A API \u8C03\u7528\u8FD4\u56DE\u7ED3\u679C\u4E2D\u7684\u67D0\u4E2A\u5B57\u6BB5\u503C\u53EF\u4EE5\u4F5C\u4E3A\u540E\u7EED API \u8C03\u7528\u7684\u8F93\u5165\u53C2\u6570\uFF1B</li><li>\u65B9\u4FBF\u5728 API \u8C03\u7528\u4E4B\u524D\u6216\u8005\u4E4B\u540E\u6267\u884C\u989D\u5916\u7684\u4EFB\u610F\u64CD\u4F5C\uFF0C\u53EF\u4EE5\u5728\u8C03\u7528\u524D\u6267\u884C\u6570\u636E\u51C6\u5907\u64CD\u4F5C\uFF0C\u53EF\u4EE5\u5728\u8C03\u7528\u540E\u6267\u884C\u73B0\u573A\u6E05\u7406\u5DE5\u4F5C\u7B49\uFF1B</li><li>\u53EF\u4EE5\u5F88\u65B9\u4FBF\u5730\u652F\u6301\u6570\u636E\u9A71\u52A8\u6D4B\u8BD5\uFF0C\u8FD9\u91CC\u7684\u6570\u636E\u9A71\u52A8\u6D4B\u8BD5\u6982\u5FF5\u548C GUI \u6D4B\u8BD5\u4E2D\u7684\u6570\u636E\u9A71\u52A8\u6D4B\u8BD5\u5B8C\u5168\u76F8\u540C\uFF0C\u4E5F\u5C31\u662F\u53EF\u4EE5\u5C06\u6D4B\u8BD5\u6570\u636E\u548C\u6D4B\u8BD5\u4EE3\u7801\u5206\u79BB\u89E3\u8026\uFF1B</li><li>\u7531\u4E8E\u76F4\u63A5\u91C7\u7528\u4E86\u4EE3\u7801\u5B9E\u73B0\uFF0C\u6240\u4EE5\u53EF\u4EE5\u66F4\u7075\u6D3B\u5730\u5904\u7406\u6D4B\u8BD5\u9A8C\u8BC1\u7684\u65AD\u8A00\uFF08Assert\uFF09\uFF1B</li><li>\u539F\u751F\u652F\u6301\u547D\u4EE4\u884C\u7684\u6D4B\u8BD5\u6267\u884C\u65B9\u5F0F\uFF0C\u53EF\u4EE5\u65B9\u4FBF\u5730\u548C CI/CD \u5DE5\u5177\u505A\u96C6\u6210\u3002</li></ol><p>\u8FD9\u91CC\u6211\u7ED9\u51FA\u4E86\u4E00\u6BB5\u4F2A\u4EE3\u7801\u793A\u4F8B\uFF0C\u7528\u4E8E\u5C55\u793A\u5982\u4F55\u7528\u4EE3\u7801\u5B9E\u73B0\u4E00\u4E2A\u7B80\u5355\u7684 API \u6D4B\u8BD5\u3002 <img src="https://static001.geekbang.org/resource/image/be/6f/be4e9d0cf1442e89831629f3f5727c6f.png" alt="\u57FA\u4E8E\u4EE3\u7801\u7684API\u6D4B\u8BD5\u7684\u4F2A\u4EE3\u7801\u793A\u4F8B"></p><ul><li>\u4EE3\u7801\u7684\u7B2C 1-12 \u884C\uFF0C\u521B\u5EFA\u4E86 CreateUserAPI \u7C7B\uFF0C\u5176\u4E2D\u5305\u542B\u4E86 endpoint\u3001\u64CD\u4F5C\u65B9\u6CD5 PUT\u3001InlineParam \u548C Param \u7684\u8BBE\u7F6E\uFF0C\u5E76\u4E14\u6784\u5EFA\u4E86\u5BF9\u5E94\u7684 request \u5BF9\u8C61\uFF1B</li><li>\u4EE3\u7801\u7684\u7B2C 14-19 \u884C\uFF0C\u662F\u6D4B\u8BD5\u7684\u4E3B\u4F53\u51FD\u6570\u3002\u8FD9\u6BB5\u51FD\u6570\u7684\u903B\u8F91\u662F\u8FD9\u6837\u7684\uFF1A <ul><li>\u9996\u5148\uFF0C\u6784\u5EFA CreateUserAPI \u7684\u5BF9\u8C61\uFF1B</li><li>\u7136\u540E\uFF0C\u7528 CreateUserAPI \u5BF9\u8C61\u7684 buildRequest \u65B9\u6CD5\u7ED3\u5408\u8F93\u5165\u53C2\u6570\u6784\u5EFA request \u5BF9\u8C61\uFF1B</li><li>\u63A5\u7740\uFF0C\u901A\u8FC7 request \u5BF9\u8C61\u7684 request()\u65B9\u6CD5\u53D1\u8D77\u4E86 API \u8C03\u7528\uFF1B</li><li>\u6700\u540E\uFF0C\u9A8C\u8BC1 response \u4E2D\u7684\u72B6\u6001\u7801\u662F\u4E0D\u662F 200\u3002</li></ul></li></ul><p>\u5728\u8FD9\u6BB5\u4F2A\u4EE3\u7801\u4E2D\uFF0C\u6709\u4EE5\u4E0B\u51E0\u70B9\u9700\u8981\u4F60\u7279\u522B\u6CE8\u610F\uFF1A</p><ol><li>\u4EE3\u7801\u4E2D\u201CCreateUserAPI \u7684\u7236\u7C7B RestAPI\u201D\u201C_buildRequest()\u65B9\u6CD5\u201D\u201Crequest()\u65B9\u6CD5\u201D\u201CaddInlineParam()\u65B9\u6CD5\u201D\u7B49\uFF0C\u90FD\u662F\u7531 API \u6D4B\u8BD5\u6846\u67B6\u63D0\u4F9B\u7684\u3002</li><li>\u4E3A\u4E86\u7B80\u5316\u4EE3\u7801\uFF0C\u8FD9\u91CC\u5E76\u6CA1\u6709\u5F15\u5165\u6570\u636E\u9A71\u52A8\u7684 data provider\u3002\u4F46\u5728\u5B9E\u9645\u9879\u76EE\u4E2D\uFF0C\u4EE3\u7801\u7B2C 14 \u884C\u7684\u6D4B\u8BD5\u8F93\u5165\u53C2\u6570\uFF0C\u5F80\u5F80\u6765\u81EA\u4E8E data provider\uFF0C\u5373\u7531\u6570\u636E\u9A71\u52A8\u7684\u65B9\u5F0F\u63D0\u4F9B\u6D4B\u8BD5\u8F93\u5165\u6570\u636E\u3002</li><li>\u7531\u4E8E\u6D4B\u8BD5\u8FC7\u7A0B\u5B8C\u5168\u7531\u4EE3\u7801\u5B9E\u73B0\uFF0C\u6240\u4EE5\u53EF\u4EE5\u5F88\u65B9\u4FBF\u7684\u5728\u6D4B\u8BD5\u6267\u884C\u524D\u540E\u589E\u52A0\u4EFB\u610F\u7684\u989D\u5916\u6B65\u9AA4\u3002\u6BD4\u5982\uFF0C\u9700\u8981\u5728 CreateUser \u524D\u589E\u52A0\u6570\u636E\u521B\u5EFA\u7684\u6B65\u9AA4\u65F6\uFF0C\u53EA\u9700\u8981\u5728\u4EE3\u7801\u7B2C 15 \u884C\u524D\u76F4\u63A5\u6DFB\u52A0\u5C31\u53EF\u4EE5\u4E86\u3002</li><li>\u8FD9\u91CC\u7684\u4F8B\u5B50\u53EA\u6709\u4E00\u4E2A API \u8C03\u7528\uFF0C\u5F53\u9700\u8981\u591A\u4E2A API \u987A\u5E8F\u8C03\u7528\u65F6\uFF0C\u76F4\u63A5\u6269\u5C55 testCreateUser \u65B9\u6CD5\u5373\u53EF\uFF0C\u4E24\u4E2A API \u4E4B\u95F4\u7684\u6570\u636E\u4F20\u9012\u53EF\u4EE5\u901A\u8FC7\u4E0A\u4E00\u4E2A API \u8FD4\u56DE\u7684 response.XXXX \u5B8C\u6210\u3002</li></ol><p>\u901A\u8FC7\u8FD9\u6BB5\u4F2A\u4EE3\u7801\uFF0C\u6211\u4EEC\u53EF\u4EE5\u770B\u5230\uFF0C\u867D\u7136\u57FA\u4E8E\u4EE3\u7801\u7684 API \u6D4B\u8BD5\u7075\u6D3B\u6027\u5F88\u597D\uFF0C\u4E5F\u53EF\u4EE5\u5F88\u65B9\u4FBF\u5730\u548C CI/CD \u96C6\u6210\uFF0C\u4F46\u662F\u4E5F\u5F15\u5165\u4E86\u4E00\u4E9B\u65B0\u7684\u95EE\u9898\uFF0C\u6BD4\u5982\uFF1A</p><ul><li>\u5BF9\u4E8E\u5355\u4E2A API \u6D4B\u8BD5\u7684\u573A\u666F\uFF0C\u5DE5\u4F5C\u91CF\u76F8\u6BD4 Postman \u8981\u5927\u5F97\u591A\uFF1B</li><li>\u5BF9\u4E8E\u5355\u4E2A API \u6D4B\u8BD5\u7684\u573A\u666F\uFF0C\u65E0\u6CD5\u76F4\u63A5\u91CD\u7528 Postman \u91CC\u9762\u5DF2\u7ECF\u79EF\u7D2F\u7684 Collection\u3002</li></ul><p>\u5728\u5B9E\u9645\u5DE5\u7A0B\u4E2D\uFF0C\u8FD9\u4E24\u4E2A\u95EE\u9898\u975E\u5E38\u91CD\u8981\uFF0C\u800C\u4E14\u5FC5\u987B\u8981\u89E3\u51B3\u3002\u56E0\u4E3A\u516C\u53F8\u7BA1\u7406\u5C42\u80AF\u5B9A\u65E0\u6CD5\u63A5\u53D7\u76F8\u540C\u5DE5\u4F5C\u7684\u5DE5\u4F5C\u91CF\u76F4\u7EBF\u4E0A\u5347\uFF0C\u540C\u65F6\u539F\u672C\u5DF2\u7ECF\u5B8C\u6210\u7684\u90E8\u5206\u65E0\u6CD5\u7EE7\u7EED\u4F7F\u7528\uFF0C\u6240\u4EE5\u81EA\u52A8\u5316\u751F\u6210 API \u6D4B\u8BD5\u4EE3\u7801\u7684\u6280\u672F\u4E5F\u5C31\u5E94\u8FD0\u800C\u751F\u4E86\u3002</p><p><strong>\u81EA\u52A8\u751F\u6210 API \u6D4B\u8BD5\u4EE3\u7801</strong></p><p>\u81EA\u52A8\u751F\u6210 API \u6D4B\u8BD5\u4EE3\u7801\u662F\u6307\uFF0C\u57FA\u4E8E Postman \u7684 Collection \u751F\u6210\u57FA\u4E8E\u4EE3\u7801\u7684 API \u6D4B\u8BD5\u7528\u4F8B\u3002</p><p>\u5176\u5B9E\uFF0C\u5728\u4E0A\u4E00\u7BC7\u6587\u7AE0\u300A\u4ECE 0 \u5230 1\uFF1AAPI \u6D4B\u8BD5\u600E\u4E48\u505A\uFF1F\u5E38\u7528 API \u6D4B\u8BD5\u5DE5\u5177\u7B80\u4ECB\u300B\u6700\u540E\u7684\u90E8\u5206\uFF0C\u6211\u5DF2\u7ECF\u63D0\u5230\u8FC7 Postman \u5DE5\u5177\u672C\u8EAB\u5DF2\u7ECF\u652F\u6301\u5C06 Collection \u8F6C\u5316\u6210\u6D4B\u8BD5\u4EE3\u7801\uFF0C\u4F46\u5982\u679C\u76F4\u63A5\u4F7F\u7528\u8FD9\u4E2A\u529F\u80FD\u7684\u8BDD\uFF0C\u8FD8\u6709\u4E24\u4E2A\u95EE\u9898\u9700\u8981\u89E3\u51B3\uFF1A</p><ol><li>\u6D4B\u8BD5\u4E2D\u7684\u65AD\u8A00\uFF08assert\uFF09\u90E8\u5206\u4E0D\u4F1A\u751F\u6210\u4EE3\u7801\uFF0C\u4E5F\u5C31\u662F\u8BF4\u6D4B\u8BD5\u4EE3\u7801\u7684\u751F\u6210\u53EA\u652F\u6301\u53D1\u8D77 request \u7684\u90E8\u5206\uFF0C\u800C\u4E0D\u4F1A\u81EA\u52A8\u751F\u6210\u6D4B\u8BD5\u9A8C\u8BC1\u70B9\u7684\u4EE3\u7801\uFF1B</li><li>\u5F88\u591A\u4E2D\u5927\u578B\u4E92\u8054\u7F51\u4F01\u4E1A\u90FD\u662F\u4F7F\u7528\u81EA\u5DF1\u5F00\u53D1\u7684 API \u6D4B\u8BD5\u6846\u67B6\uFF0C\u90A3\u4E48\u6D4B\u8BD5\u4EE3\u7801\u7684\u5B9E\u73B0\u5C31\u4F1A\u548C\u81EA\u7814 API \u6D4B\u8BD5\u6846\u67B6\u7ED1\u5B9A\u5728\u4E00\u8D77\uFF0C\u663E\u7136 Postman \u5E76\u4E0D\u652F\u6301\u8FD9\u7C7B\u4EE3\u7801\u7684\u81EA\u52A8\u751F\u6210\u3002</li></ol><p>\u9274\u4E8E\u4EE5\u4E0A\u4E24\u70B9\uFF0C\u7406\u60F3\u7684\u505A\u6CD5\u662F\u81EA\u5DF1\u5B9E\u73B0\u4E00\u4E2A\u4EE3\u7801\u751F\u6210\u5DE5\u5177\uFF0C\u8FD9\u4E2A\u5DE5\u5177\u7684\u8F93\u5165\u662F Postman \u4E2D Collection \u7684 JSON \u6587\u4EF6\uFF0C\u8F93\u51FA\u662F\u57FA\u4E8E\u81EA\u7814 API \u6846\u67B6\u7684\u6D4B\u8BD5\u4EE3\u7801\uFF0C\u800C\u4E14\u540C\u65F6\u4F1A\u628A\u6D4B\u8BD5\u7684\u65AD\u8A00\u4E00\u5E76\u8F6C\u5316\u4E3A\u4EE3\u7801\u3002</p><p><strong>\u8FD9\u4E2A\u5C0F\u5DE5\u5177\u5B9E\u73B0\u8D77\u6765\u5E76\u4E0D\u590D\u6742\uFF0C\u5176\u672C\u8D28\u5C31\u662F\u89E3\u6790 Collection JSON \u6587\u4EF6\u7684\u5404\u4E2A\u90E8\u5206\uFF0C\u7136\u540E\u6839\u636E\u81EA\u7814 API \u6846\u67B6\u7684\u4EE3\u7801\u6A21\u677F\u5B9E\u73B0\u53D8\u91CF\u66FF\u6362</strong>\u3002 \u5177\u4F53\u6765\u8BB2\uFF0C\u5B9E\u73B0\u8FC7\u7A0B\u5927\u81F4\u53EF\u4EE5\u5206\u4E3A\u4EE5\u4E0B\u4E09\u6B65\uFF1A</p><ul><li>\u9996\u5148\uFF0C\u6839\u636E\u81EA\u7814 API \u6846\u67B6\u7684\u4EE3\u7801\u7ED3\u6784\u5EFA\u7ACB\u4E00\u4E2A\u5E26\u6709\u53D8\u91CF\u5360\u4F4D\u7B26\u7684\u6A21\u677F\u6587\u4EF6\uFF1B</li><li>\u7136\u540E\uFF0C\u901A\u8FC7 JSON \u89E3\u6790\u7A0B\u5E8F\uFF0C\u6309\u7167 Collection JSON \u6587\u4EF6\u7684\u683C\u5F0F\u5B9A\u4E49\u53BB\u63D0\u53D6 header\u3001method \u7B49\u4FE1\u606F\uFF1B</li><li>\u6700\u540E\uFF0C\u7528\u63D0\u53D6\u5F97\u5230\u7684\u5177\u4F53\u503C\u66FF\u6362\u4E4B\u524D\u6A21\u677F\u6587\u4EF6\u4E2D\u7684\u53D8\u91CF\u5360\u4F4D\u7B26\uFF0C\u8FD9\u6837\u5C31\u5F97\u5230\u4E86\u53EF\u6267\u884C\u7684\u81EA\u7814\u6846\u67B6\u7684 API \u6D4B\u8BD5\u7528\u4F8B\u4EE3\u7801\u3002</li></ul><p>\u6709\u4E86\u8FD9\u4E2A\u5DE5\u5177\u540E\uFF0C\u6211\u5EFA\u8BAE\u4F60\u7684\u5DE5\u4F5C\u6A21\u5F0F\uFF08Working Model\uFF09\u53EF\u4EE5\u8F6C\u6362\u6210\u8FD9\u6837\uFF1A</p><ul><li>\u5BF9\u4E8E Postman \u4E2D\u5DF2\u7ECF\u7D2F\u79EF\u7684 Collection\uFF0C\u5168\u90E8\u7531\u8FD9\u4E2A\u5DE5\u5177\u7EDF\u4E00\u8F6C\u6362\u6210\u57FA\u4E8E\u4EE3\u7801\u7684 API \u6D4B\u8BD5\u7528\u4F8B\uFF1B</li><li>\u5F00\u53D1\u4EBA\u5458\u7EE7\u7EED\u4F7F\u7528 Postman \u6267\u884C\u57FA\u672C\u7684\u6D4B\u8BD5\uFF0C\u5E76\u5C06\u6240\u6709\u6D4B\u8BD5\u7528\u4F8B\u4FDD\u5B58\u6210 Collection\uFF0C\u540E\u7EED\u7EDF\u4E00\u7531\u5DE5\u5177\u8F6C\u6362\u6210\u57FA\u4E8E\u4EE3\u7801\u7684 API \u6D4B\u8BD5\u7528\u4F8B\uFF1B</li><li>\u5BF9\u4E8E\u590D\u6742\u6D4B\u8BD5\u573A\u666F\uFF08\u6BD4\u5982\uFF0C\u987A\u5E8F\u8C03\u7528\u591A\u4E2A API \u7684\u6D4B\u8BD5\uFF09\uFF0C\u53EF\u4EE5\u7EC4\u88C5\u7531\u5DE5\u5177\u8F6C\u6362\u5F97\u5230\u7684 API \u6D4B\u8BD5\u7528\u4F8B\u4EE3\u7801\uFF0C\u5B8C\u6210\u6D4B\u8BD5\u5DE5\u4F5C\u3002</li></ul><p>\u5982\u56FE 2 \u6240\u793A\uFF0C\u5C31\u662F\u4E00\u4E2A\u7EC4\u88C5\u591A\u4E2A\u7531\u5DE5\u5177\u8F6C\u6362\u5F97\u5230\u7684 API \u6D4B\u8BD5\u7528\u4F8B\u4EE3\u7801\u7684\u4F8B\u5B50\u3002\u5176\u4E2D\uFF0C\u4EE3\u7801\u7B2C 3 \u884C\u7684\u7C7B\u201CCreateUserAPI\u201D\u548C\u7B2C 10 \u884C\u7684\u7C7B\u201CBindCreditCardAPI\u201D\u7684\u5177\u4F53\u4EE3\u7801\u5C31\u53EF\u4EE5\u901A\u8FC7\u5DE5\u5177\u8F6C\u6362\u5F97\u5230\u3002</p><p><img src="https://static001.geekbang.org/resource/image/8c/e9/8cc97f6e1459aac8aedbb14ab8bec4e9.png" alt="\u591A\u4E2AAPI\u987A\u5E8F\u8C03\u7528\u7684\u6D4B\u8BD5\u7528\u4F8B\u4EE3\u7801"></p><p>\u81F3\u6B64\uFF0C\u57FA\u4E8E\u4EE3\u7801\u7684 API \u6D4B\u8BD5\u53D1\u5C55\u5F97\u7B97\u662F\u6BD4\u8F83\u6210\u719F\u4E86\uFF0C\u4F46\u5728\u5B9E\u9645\u5E94\u7528\u8FC7\u7A0B\u4E2D\u8FD8\u6709\u4E00\u4E2A\u75DB\u70B9\u4E00\u76F4\u672A\u88AB\u89E3\u51B3\uFF0C\u90A3\u5C31\u662F\u6D4B\u8BD5\u9A8C\u8BC1\u4E2D\u7684\u65AD\u8A00\uFF0C\u4E5F\u662F\u6211\u63A5\u4E0B\u6765\u8981\u548C\u4F60\u4E00\u8D77\u8BA8\u8BBA\u7684\u8BDD\u9898\u3002</p><p>Response \u7ED3\u679C\u53D1\u751F\u53D8\u5316\u65F6\u7684\u81EA\u52A8\u8BC6\u522B \u5728\u5B9E\u9645\u7684\u5DE5\u7A0B\u9879\u76EE\u4E2D\uFF0C\u5F00\u53D1\u4E86\u5927\u91CF\u7684\u57FA\u4E8E\u4EE3\u7801\u7684 API \u6D4B\u8BD5\u7528\u4F8B\u540E\uFF0C\u4F60\u4F1A\u53D1\u73B0\u4E00\u4E2A\u8BA9\u4EBA\u5F88\u7EA0\u7ED3\u7684\u95EE\u9898\uFF1A\u5230\u5E95\u5E94\u8BE5\u9A8C\u8BC1 API \u8FD4\u56DE\u7ED3\u679C\u4E2D\u7684\u54EA\u4E9B\u5B57\u6BB5\uFF1F</p><p>\u56E0\u4E3A\u4F60\u4E0D\u53EF\u80FD\u5BF9\u8FD4\u56DE\u7ED3\u679C\u4E2D\u7684\u6BCF\u4E00\u4E2A\u5B57\u6BB5\u90FD\u5199 assert\uFF0C\u901A\u5E38\u60C5\u51B5\u4E0B\uFF0C\u4F60\u53EA\u4F1A\u9488\u5BF9\u5173\u6CE8\u7684\u51E0\u4E2A\u5B57\u6BB5\u5199 assert\uFF0C\u800C\u90A3\u4E9B\u6CA1\u5199 assert \u7684\u5B57\u6BB5\u4E5F\u5C31\u65E0\u6CD5\u88AB\u5173\u6CE8\u4E86\u3002</p><p>\u4F46\u5BF9 API \u6D4B\u8BD5\u6765\u8BF4\uFF0C\u6709\u4E00\u4E2A\u5F88\u91CD\u8981\u7684\u6982\u5FF5\u662F\u540E\u5411\u517C\u5BB9\u6027\uFF08backward compatibility\uFF09\u3002API \u7684\u540E\u5411\u517C\u5BB9\u6027\u662F\u6307\uFF0C\u53D1\u5E03\u7684\u65B0 API \u7248\u672C\u5E94\u8BE5\u80FD\u591F\u517C\u5BB9\u8001\u7248\u672C\u7684 API\u3002</p><p>\u540E\u5411\u517C\u5BB9\u6027\u9664\u4E86\u8981\u6C42 API \u7684\u8C03\u7528\u53C2\u6570\u4E0D\u80FD\u53D1\u751F\u53D8\u5316\u5916\uFF0C\u8FD8\u8981\u6C42\u4E0D\u80FD\u5220\u51CF\u6216\u8005\u4FEE\u6539\u8FD4\u56DE\u7684 response \u4E2D\u7684\u5B57\u6BB5\u3002\u56E0\u4E3A\u8FD9\u4E9B\u8FD4\u56DE\u7684 response \u4F1A\u88AB\u4E0B\u6E38\u7684\u4EE3\u7801\u4F7F\u7528\uFF0C\u5982\u679C\u5B57\u6BB5\u88AB\u5220\u51CF\u3001\u6539\u540D\u6216\u8005\u5B57\u6BB5\u503C\u53D1\u751F\u4E86\u975E\u9884\u671F\u7684\u53D8\u5316\uFF0C\u90A3\u4E48\u4E0B\u6E38\u7684\u4EE3\u7801\u5C31\u53EF\u80FD\u56E0\u4E3A\u65E0\u6CD5\u627E\u5230\u539F\u672C\u7684\u5B57\u6BB5\uFF0C\u6216\u8005\u56E0\u4E3A\u5B57\u6BB5\u503C\u7684\u53D8\u5316\u800C\u53D1\u751F\u95EE\u9898\uFF0C\u4ECE\u800C\u7834\u574F API \u7684\u540E\u5411\u517C\u5BB9\u6027\u3002</p><p>\u6240\u4EE5\uFF0C\u6211\u4EEC\u8FEB\u5207\u9700\u8981\u627E\u5230\u4E00\u4E2A\u65B9\u6CD5\uFF0C\u65E2\u53EF\u4EE5\u4E0D\u5BF9\u6240\u6709\u7684 response \u5B57\u6BB5\u90FD\u53BB\u5199 assert\uFF0C\u53C8\u53EF\u4EE5\u76D1\u6D4B\u5230 response \u7684\u7ED3\u6784\u4EE5\u53CA\u6CA1\u6709\u5199 assert \u7684\u5B57\u6BB5\u503C\u7684\u53D8\u5316\u3002</p><p>\u5728\u8FD9\u6837\u7684\u80CC\u666F\u4E0B\uFF0C\u8BDE\u751F\u4E86\u201CResponse \u7ED3\u679C\u53D8\u5316\u65F6\u7684\u81EA\u52A8\u8BC6\u522B\u201D\u6280\u672F\u3002\u4E5F\u5C31\u662F\u8BF4\uFF0C\u5373\u4F7F\u6211\u4EEC\u6CA1\u6709\u9488\u5BF9\u6BCF\u4E2A response \u5B57\u6BB5\u90FD\u53BB\u5199 assert\uFF0C\u6211\u4EEC\u4ECD\u7136\u53EF\u4EE5\u8BC6\u522B\u51FA\u54EA\u4E9B response \u5B57\u6BB5\u53D1\u751F\u4E86\u53D8\u5316\u3002</p><p>\u5177\u4F53\u5B9E\u73B0\u7684\u601D\u8DEF\u662F\uFF0C\u5728 API \u6D4B\u8BD5\u6846\u67B6\u91CC\u5F15\u5165\u4E00\u4E2A\u5185\u5EFA\u6570\u636E\u5E93\uFF0C\u63A8\u8350\u91C7\u7528\u975E\u5173\u7CFB\u578B\u6570\u636E\u5E93\uFF08\u6BD4\u5982 MongoDB\uFF09\uFF0C\u7136\u540E\u7528\u8FD9\u4E2A\u6570\u636E\u5E93\u8BB0\u5F55\u6BCF\u6B21\u8C03\u7528\u7684 request \u548C response \u7684\u7EC4\u5408\uFF0C\u5F53\u4E0B\u6B21\u53D1\u9001\u76F8\u540C request \u65F6\uFF0CAPI \u6D4B\u8BD5\u6846\u67B6\u5C31\u4F1A\u81EA\u52A8\u548C\u4E0A\u6B21\u7684 response \u505A\u5DEE\u5F02\u68C0\u6D4B\uFF0C\u5BF9\u4E8E\u6709\u53D8\u5316\u7684\u5B57\u6BB5\u7ED9\u51FA\u544A\u8B66\u3002</p><p>\u4F60\u53EF\u80FD\u4F1A\u8BF4\u8FD9\u79CD\u505A\u6CD5\u4E5F\u6709\u95EE\u9898\uFF0C\u56E0\u4E3A\u6709\u4E9B\u5B57\u6BB5\u7684\u503C\u6BCF\u6B21 API \u8C03\u7528\u90FD\u662F\u4E0D\u540C\u7684\uFF0C\u6BD4\u5982 token \u503C\u3001session ID\u3001\u65F6\u95F4\u6233\u7B49\uFF0C\u8FD9\u6837\u6BCF\u6B21\u7684\u8C03\u7528\u5C31\u90FD\u4F1A\u6709\u544A\u8B66\u3002</p><p>\u4F46\u662F\u8FD9\u4E2A\u95EE\u9898\u5F88\u597D\u89E3\u51B3\uFF0C\u73B0\u5728\u7684\u89E3\u51B3\u529E\u6CD5\u662F\u901A\u8FC7\u89C4\u5219\u914D\u7F6E\u8BBE\u7ACB\u4E00\u4E2A\u201C\u767D\u540D\u5355\u5217\u8868\u201D\uFF0C\u628A\u90A3\u4E9B\u52A8\u6001\u503C\u7684\u5B57\u6BB5\u6392\u9664\u5728\u5916\u3002</p><p><strong>\u603B\u7ED3</strong></p><p>\u4E3A\u4E86\u8BA9\u4F60\u53EF\u4EE5\u66F4\u597D\u5730\u7406\u89E3\u4ECA\u5929\u7684 API \u6D4B\u8BD5\u6846\u67B6\uFF0C\u6211\u4ECE\u5176\u53D1\u5C55\u5386\u7A0B\u7684\u89D2\u5EA6\u8FDB\u884C\u4E86\u5206\u6790\uFF1A</p><p>\u65E9\u671F\u7684\u57FA\u4E8E Postman \u7684 API \u6D4B\u8BD5\u5728\u9762\u4E34\u9891\u7E41\u6267\u884C\u5927\u91CF\u6D4B\u8BD5\u7528\u4F8B\uFF0C\u4EE5\u53CA\u4E0E CI/CD \u6D41\u6C34\u7EBF\u6574\u5408\u7684\u95EE\u9898\u65F6\uFF0C\u663E\u5F97\u5FC3\u6709\u4F59\u800C\u529B\u4E0D\u8DB3\u3002\u4E3A\u6B64\uFF0C\u57FA\u4E8E\u547D\u4EE4\u884C\u7684 API \u6D4B\u8BD5\u5B9E\u8DF5\uFF0C\u4E5F\u5C31\u662F Postman+Newman\uFF0C\u5177\u6709\u5F88\u597D\u7684\u7075\u6D3B\u6027\uFF0C\u89E3\u51B3\u4E86\u8FD9\u4E24\u4E2A\u95EE\u9898\u3002</p><p>\u4F46\u662F\uFF0CPostman+Newman \u7684\u6D4B\u8BD5\u65B9\u6848\uFF0C\u53EA\u80FD\u9002\u7528\u4E8E\u5355\u4E2A API \u8C03\u7528\u7684\u7B80\u5355\u6D4B\u8BD5\u573A\u666F\uFF0C\u5BF9\u4E8E\u8FDE\u7EED\u8C03\u7528\u591A\u4E2A API \u5E76\u6D89\u53CA\u5230\u53C2\u6570\u4F20\u9012\u95EE\u9898\u65F6\uFF0C\u8FD9\u4E2A\u65B9\u6848\u5C31\u53D8\u5F97\u4E0D\u90A3\u4E48\u7406\u60F3\u548C\u5B8C\u7F8E\u4E86\u3002\u968F\u540E\uFF0CAPI \u6D4B\u8BD5\u5C31\u8FC7\u6E21\u5230\u4E86\u57FA\u4E8E\u4EE3\u7801\u7684 API \u6D4B\u8BD5\u9636\u6BB5\u3002</p><p>\u4E00\u4E9B\u5C0F\u578B\u4F01\u4E1A\uFF0C\u5219\u5F80\u5F80\u4F1A\u9009\u62E9\u9002\u5408\u81EA\u5DF1\u4E1A\u52A1\u7684\u6210\u719F API \u6D4B\u8BD5\u6846\u67B6\u3002\u4E2D\u5927\u578B\u7684\u4E92\u8054\u7F51\u4F01\u4E1A\uFF0C\u4E00\u822C\u90FD\u4F1A\u6839\u636E\u81EA\u5DF1\u7684\u4E1A\u52A1\u4E0A\u4E0B\u6587\uFF0C\u5728\u6210\u719F API \u6D4B\u8BD5\u6846\u67B6\u7684\u57FA\u7840\u4E0A\u5C01\u88C5\u81EA\u5DF1\u7684 API \u6D4B\u8BD5\u6846\u67B6\uFF0C\u63D0\u5347\u6D4B\u8BD5\u6548\u7387\u548C\u7075\u6D3B\u6027\u3002</p><p>\u4F46\u662F\uFF0C\u4E0D\u7BA1\u662F\u91C7\u7528\u73B0\u6210\u7684\u8FD8\u662F\u81EA\u5DF1\u53BB\u5F00\u53D1 API \u6D4B\u8BD5\u6846\u67B6\uFF0C\u90FD\u4F1A\u9047\u5230\u6D4B\u8BD5\u7528\u4F8B\u5F00\u53D1\u6548\u7387\u4F4E\u4E0B\uFF0C\u4EE5\u53CA\u65E0\u6CD5\u76F4\u63A5\u91CD\u7528 Postman \u4E2D\u79EF\u7D2F\u7684 Collection \u7684\u95EE\u9898\uFF0C\u4E3A\u6B64\u6211\u5206\u4EAB\u4E86\u4E24\u4E2A\u6BD4\u8F83\u597D\u7528\u7684\u65B9\u6CD5\uFF0C\u4E5F\u5C31\u662F\uFF1A\u81EA\u52A8\u751F\u6210 API \u6D4B\u8BD5\u4EE3\u7801\u548C Response \u7ED3\u679C\u53D8\u5316\u7684\u81EA\u52A8\u8BC6\u522B\uFF0C\u5E76\u7ED9\u51FA\u4E86\u8FD9\u4E24\u4E2A\u65B9\u6CD5\u7684\u5B9E\u73B0\u601D\u8DEF\u3002</p><p>\u5E0C\u671B\u6211\u5206\u4EAB\u7684\u8FD9\u4E9B\u5185\u5BB9\uFF0C\u53EF\u4EE5\u5E2E\u4F60\u89E3\u51B3\u5728\u5B9E\u9645\u6D4B\u8BD5\u9879\u76EE\u4E2D\u9047\u5230\u7684\u95EE\u9898\u3002</p><p><strong>\u601D\u8003\u9898</strong></p><p>\u76EE\u524D\uFF0C\u57FA\u4E8E\u4EE3\u7801\u7684 API \u6D4B\u8BD5\u6846\u67B6\u5DF2\u7ECF\u6BD4\u8F83\u6210\u719F\u4E86\uFF0C\u6240\u4EE5\u5728\u6B64\u57FA\u7840\u4E0A\u53C8\u51FA\u73B0\u4E86\u57FA\u4E8E\u914D\u7F6E\u6587\u4EF6\u7684 API \u6D4B\u8BD5\u6846\u67B6\uFF0C\u6BD4\u5982\u5178\u578B\u7684 HttpRunner\uFF0C\u5728\u6B64\u7C7B API \u6D4B\u8BD5\u6846\u67B6\u7684\u652F\u6301\u4E0B\uFF0C\u6D4B\u8BD5\u7528\u4F8B\u672C\u8EAB\u5F80\u5F80\u5C31\u662F\u7EAF\u7CB9\u7684\u914D\u7F6E\u6587\u4EF6\u4E86\u3002\u4F60\u662F\u5426\u6709\u63A5\u89E6\u8FC7\u8FD9\u7C7B API \u6D4B\u8BD5\u6846\u67B6\uFF0C\u5BF9\u6B64\u53C8\u6709\u4EC0\u4E48\u770B\u6CD5\u5462\uFF1F</p>',57);function t(I,l){return p}var i=e(P,[["render",t],["__file","23.html.vue"]]);export{i as default};
